-- Statement 1/32
-- Bizim Mekanlar v2.8.0
-- In-app content sharing for places, notes, collections and profiles.

begin;

-- Statement 2/32
create table if not exists public."ContentShares" (
  "ContentShareId" bigint generated by default as identity primary key,
  "SenderUserId" integer not null references public."Users"("UserId"),
  "RecipientUserId" integer not null references public."Users"("UserId"),
  "ShareTypeCode" varchar(20) not null,
  "PlaceId" integer null,
  "PlaceNoteId" integer null,
  "UserPlaceListId" bigint null,
  "ProfileUserId" integer null,
  "Message" varchar(100) null,
  "TargetTitle" varchar(180) not null,
  "TargetSubtitle" varchar(220) null,
  "TargetPublicId" uuid null,
  "TargetUsername" varchar(30) null,
  "IsRead" boolean not null default false,
  "ReadDate" timestamptz null,
  "PushSentDate" timestamptz null,
  "IsActive" boolean not null default true,
  "CreatedDate" timestamptz not null default now(),
  "UpdatedDate" timestamptz null,
  constraint "CK_ContentShares_DifferentUsers"
    check ("SenderUserId" <> "RecipientUserId"),
  constraint "CK_ContentShares_Type"
    check ("ShareTypeCode" in ('PLACE', 'NOTE', 'COLLECTION', 'PROFILE')),
  constraint "CK_ContentShares_Target"
    check (
      ("ShareTypeCode" = 'PLACE' and "PlaceId" is not null and "PlaceNoteId" is null and "UserPlaceListId" is null and "ProfileUserId" is null)
      or ("ShareTypeCode" = 'NOTE' and "PlaceId" is null and "PlaceNoteId" is not null and "UserPlaceListId" is null and "ProfileUserId" is null)
      or ("ShareTypeCode" = 'COLLECTION' and "PlaceId" is null and "PlaceNoteId" is null and "UserPlaceListId" is not null and "ProfileUserId" is null)
      or ("ShareTypeCode" = 'PROFILE' and "PlaceId" is null and "PlaceNoteId" is null and "UserPlaceListId" is null and "ProfileUserId" is not null)
    )
);

-- Statement 3/32
create index if not exists "IX_ContentShares_RecipientCreated"
  on public."ContentShares" ("RecipientUserId", "CreatedDate" desc)
  where "IsActive" = true;

-- Statement 4/32
create index if not exists "IX_ContentShares_SenderCreated"
  on public."ContentShares" ("SenderUserId", "CreatedDate" desc)
  where "IsActive" = true;

-- Statement 5/32
create index if not exists "IX_ContentShares_RecipientUnread"
  on public."ContentShares" ("RecipientUserId", "IsRead", "CreatedDate" desc)
  where "IsActive" = true;

-- Statement 6/32
alter table public."ContentShares" enable row level security;

-- Statement 7/32
drop policy if exists "ContentShares_SelectParticipants" on public."ContentShares";

-- Statement 8/32
create policy "ContentShares_SelectParticipants"
on public."ContentShares"
for select
to authenticated
using (
  "SenderUserId" = public."GetMySessionUserId"()
  or "RecipientUserId" = public."GetMySessionUserId"()
);

-- Statement 9/32
revoke all on table public."ContentShares" from anon, authenticated;

-- Statement 10/32
grant select on table public."ContentShares" to authenticated, service_role;

-- Statement 11/32
grant all on table public."ContentShares" to service_role;

